import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { ToastContainer } from 'react-toastify';
import { handleError, handleSuccess } from '../utils';
import './Login.css';
import FoodImage from '../pages/1.png';

function Login() {
  const [loginInfo, setLoginInfo] = useState({ email: '', password: '' });
  const [showForgotPassword, setShowForgotPassword] = useState(false);
  const [resetEmail, setResetEmail] = useState('');
  const navigate = useNavigate();

  const handleChange = (e) => {
    const { name, value } = e.target;
    setLoginInfo((prev) => ({ ...prev, [name]: value }));
  };

  const handleLogin = async (e) => {
    e.preventDefault();
    const { email, password } = loginInfo;
    if (!email || !password) return handleError('Email and password are required');

    try {
      const response = await fetch('http://localhost:5001/auth/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(loginInfo),
      });
      const result = await response.json();
      const { success, message, jwtToken, name, error } = result;

      if (success) {
        handleSuccess(message);
        localStorage.setItem('token', jwtToken);
        localStorage.setItem('loggedInUser', name);
        setTimeout(() => navigate('/home'), 1000);
      } else {
        handleError(error?.details?.[0]?.message || message);
      }
    } catch (err) {
      handleError(err.message);
    }
  };

  const handleForgotPassword = async () => {
    if (!resetEmail) return handleError('Please enter your email');

    try {
      const response = await fetch('http://localhost:5001/auth/forgot-password', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email: resetEmail }),
      });
      const result = await response.json();
      if (result.success) {
        handleSuccess(result.message);
        setShowForgotPassword(false);
      } else {
        handleError(result.message);
      }
    } catch (err) {
      handleError(err.message);
    }
  };

  return (
    <div className="login-container">
      <div className="login-box">
        <div className="login-image">
          <img src={FoodImage} alt='Food Illustration' />
        </div>
        <div className="login-form">
          <h2>Login to Account</h2>
          <p>Please enter your email and password to continue</p>
          <form onSubmit={handleLogin}>
            <div className="form-group">
              <label>Email Address</label>
              <input type="email" name="email" placeholder="Email Address" value={loginInfo.email} onChange={handleChange} className="form-control" />
            </div>
            <div className="form-group">
              <label>Password</label>
              <input type="password" name="password" placeholder="Password" value={loginInfo.password} onChange={handleChange} className="form-control" />
            </div>

            <p className="forgot-password" onClick={() => setShowForgotPassword(true)}>Forgot Password?</p>
            <button type="submit" className="btn btn-primary login-btn">Sign In</button>
            <p className="create-account">Don't have an account? <Link to="/signup">Create Account</Link></p>
          </form>
        </div>
      </div>

      {showForgotPassword && (
        <div className="modal-overlay">
          <div className="modal">
            <span className="close" onClick={() => setShowForgotPassword(false)}>&times;</span>
            <h3>Forgot Password?</h3>
            <p>Enter your email to recover your password</p>
            <input
              type="email"
              placeholder="Email Address"
              value={resetEmail}
              onChange={(e) => setResetEmail(e.target.value)}
              className="form-control"
            />
            <button className="btn btn-danger" onClick={handleForgotPassword}>Reset Password</button>
          </div>
        </div>
      )}

      <ToastContainer />
    </div>
  );
}

export default Login;
